"""
Installer: Slack agent + Klaviyo deployer + DB migrations.
Run: python3 install_unified_agent.py
"""
import base64, os, psycopg

def write(path, b64):
    os.makedirs(os.path.dirname(path) if os.path.dirname(path) else '.', exist_ok=True)
    open(path,'wb').write(base64.b64decode(b64))
    print('  wrote ' + path)

FILES = {
    'agents/slack_agent.py': '',
    'agents/klaviyo_deployer.py': '',
    'agents/__init__.py': '',
    'db/migrations/007_attribution_flags.sql': '',
    'db/migrations/008_agent_state.sql': '',
}
for path, b64 in FILES.items():
    write(path, b64)

# Run DB migrations
print('Running migrations...')
try:
    with psycopg.connect(os.environ['DATABASE_URL']) as conn:
        for n, name in [('007','attribution_flags'),('008','agent_state')]:
            sql = open('db/migrations/' + n + '_' + name + '.sql').read()
            conn.execute(sql)
        conn.commit()
    print('  migrations 007+008 applied')
except Exception as e:
    print('  migration note: ' + str(e))

print('''
Done. Next steps:
1. Add SLACK_BOT_TOKEN to Replit Secrets
   (create Slack app at api.slack.com, scopes: channels:history channels:read chat:write)
2. Add NEW_EPISODES_CHANNEL_ID to Replit Secrets
   (right-click #beezy-new-episodes in Slack -> Copy link -> last part is channel ID)
3. Update BEEZY_AGENTS_CHANNEL in agents/slack_agent.py with your actual channel ID
4. Invite your Slack bot to #beezy-agents and #beezy-new-episodes

Boris can then type in #beezy-agents:
  approved          -> approve current month calendar
  approved week     -> approve the 7-day plan
  deploy campaigns  -> run today orchestrator
  what is revenue   -> pull pacing data
  deploy latest episode -> deploy from #beezy-new-episodes
  status            -> see today dispatch log
''')
